import logo from './logo.png';
import './App.css';

function Logo() {
  return <img src={logo} className="App-logo" alt="logo"/>;
}

function App() {
  return (
    <div className="App">

      <header className="App-header">
        <Logo />
        <div>
          <h1>
            Goosecollab
          </h1>
          <p className="Description">
            A platform for UWaterloo Engineering students that
            allows engineers to find other engineers for their capstone projects
          </p>
        </div>
      </header>

      <div className="Description">

        <p>
          Made for EngHacks 2026, by Arulini, Franklin, Girish, and Jeff!
        </p>
      </div>

    </div>
  );
}

export default App;
